# One block per row; do a simple Hillis-Steele scan in shared memory.
# Cap shared memory length at 1024 elements; for wider rows, use a sequential fallback on GPU.
@cuda.jit
def row_scan_kernel(inp_u8, out_i64, ncols):
    row = cuda.blockIdx.x
    tid = cuda.threadIdx.x

    sm = cuda.shared.array(shape=1024, dtype=np.int64)

    if ncols <= 1024:
        if tid < ncols:
            sm[tid] = inp_u8[row, tid]
        else:
            sm[tid] = 0
        cuda.syncthreads()

        offset = 1
        while offset < ncols:
            val = 0
            if tid < ncols and tid >= offset:
                val = sm[tid - offset]
            cuda.syncthreads()
            if tid < ncols:
                sm[tid] += val
            cuda.syncthreads()
            offset *= 2

        if tid < ncols:
            out_i64[row, tid] = sm[tid]
    else:
        # Wider than shared capacity: do sequential scan by one thread.
        if tid == 0:
            s = 0
            for c in range(ncols):
                s += int(inp_u8[row, c])
                out_i64[row, c] = s

