@cuda.jit
def _kernel(inp, lo_, hi_, off_, out, n_):
    tid = cuda.threadIdx.x
    if tid >= 32:
        return

    if tid < n_:
        v = inp[tid]
        if v < lo_:
            v = lo_
        elif v > hi_:
            v = hi_
        v = v + off_
    else:
        v = np.int32(0)

