    mask = 0xFFFFFFFF
    offset2 = 1
    while offset2 < 32:
        t = cuda.shfl_up_sync(mask, v, offset2)
        if tid >= offset2:
            v = v + t
        offset2 *= 2

    if tid < n_:
        out[tid] = v

