@cuda.jit
def k_blur_and_flag(inp, out_blur, status):
    r, c = cuda.grid(2)
    pred = (r < out_blur.shape[0]) and (c < out_blur.shape[1])
    if pred:
        acc = 0.0
        for dr in (-1, 0, 1):
