        # Compare lane 0's predicate with lane (0^lane_mask), where lane_mask=0 -> lane 0.
        # This makes the flag deterministic and still exercises a warp shuffle intrinsic.
        same_as_lane0 = cuda.intrinsic_wrapper.shfl_xor_sync(mask, 1 if pred else 0, 0)
