@cuda.jit
def k_row_chunk_sums(blur, cs, scale_f, bias_f, lo_f, hi_f, out_sums):
    r = cuda.blockIdx.x
    tid = cuda.threadIdx.x
    if r >= blur.shape[0]:
        return

    chunks = out_sums.shape[1]
    for k in range(chunks):
        start = k * cs
        end = start + cs
        if end > blur.shape[1]:
            end = blur.shape[1]

        acc = np.float32(0.0)
        c = start + tid
        while c < end:
            v = blur[r, c] * scale_f + bias_f
            if v < lo_f:
                v = lo_f
            elif v > hi_f:
                v = hi_f
            acc += v
            c += cuda.blockDim.x

        # Block reduction in shared memory (assumes threads <= 256)
        sm = cuda.shared.array(256, dtype=np.float32)
        if tid < 256:
            sm[tid] = acc
        cuda.syncthreads()

        stride = cuda.blockDim.x // 2
        while stride > 0:
            if tid < stride:
                sm[tid] += sm[tid + stride]
            cuda.syncthreads()
            stride //= 2

        if tid == 0:
            out_sums[r, k] = sm[0]

